#include <omp.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#include "./main.h"

void kernel_cpu(par_str par, dim_str dim, box_str* box, FOUR_VECTOR* rv, fp* qv, FOUR_VECTOR* fv) {
    fp a2 = 2.0 * par.alpha * par.alpha;

    #pragma omp parallel for
    for (long bx = 0; bx < dim.number_boxes; bx++) {
        int first_i = box[bx].offset;
        FOUR_VECTOR* rA = &rv[first_i];
        FOUR_VECTOR* fA = &fv[first_i];

        FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];

        for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
            rA_shared[wtx] = rA[wtx];
        }

        for (int k = 0; k < (1 + box[bx].nn); k++) {
            int pointer;
            if (k == 0) {
                pointer = bx;
            } else {
                pointer = box[bx].nei[k-1].number;
            }

            int first_j = box[pointer].offset;
            FOUR_VECTOR* rB = &rv[first_j];
            fp* qB = &qv[first_j];

            FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
            fp qB_shared[NUMBER_PAR_PER_BOX];

            for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
                rB_shared[wtx] = rB[wtx];
                qB_shared[wtx] = qB[wtx];
            }

            for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
                for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                    fp r2 = (fp)rA_shared[wtx].v + (fp)rB_shared[j].v - DOT((fp)rA_shared[wtx], (fp)rB_shared[j]);
                    fp u2 = a2 * r2;
                    fp vij = exp(-u2);
                    fp fs = 2 * vij;

                    THREE_VECTOR d;
                    d.x = (fp)rA_shared[wtx].x - (fp)rB_shared[j].x;
                    fp fxij = fs * d.x;
                    d.y = (fp)rA_shared[wtx].y - (fp)rB_shared[j].y;
                    fp fyij = fs * d.y;
                    d.z = (fp)rA_shared[wtx].z - (fp)rB_shared[j].z;
                    fp fzij = fs * d.z;

                    fA[wtx].v += (double)((fp)qB_shared[j] * vij);
                    fA[wtx].x += (double)((fp)qB_shared[j] * fxij);
                    fA[wtx].y += (double)((fp)qB_shared[j] * fyij);
                    fA[wtx].z += (double)((fp)qB_shared[j] * fzij);
                }
            }
        }
    }
}
